function filterProducts(keyword) {
  const normalized = String(keyword || "").trim().toLowerCase();
  if (!normalized) {
    return products;
  }

  return products.filter((product) => {
    const text = [
      product.model,
      product.category,
      product.name,
      product.specs.join(" ")
    ].join(" ").toLowerCase();
    return text.includes(normalized);
  });
}

function groupProductsByCategory(sourceProducts) {
  const groups = [];
  const groupMap = {};
  (sourceProducts || products).forEach((product) => {
    const category = product.category || "未分类";
    if (!groupMap[category]) {
      groupMap[category] = {
        category,
        open: groups.length === 0,
        products: []
      };
      groups.push(groupMap[category]);
    }
    groupMap[category].products.push(product);
  });
  return groups;
}

module.exports = {
  products,
  filterProducts,
  groupProductsByCategory
};
